#include <iostream>

int main()
{
    int lo, hi;
    std::cin >> lo >> hi;

    for (int i = lo; i <= hi; ++i)
    {
        switch (i % 3)
        {
            case 0:
                std::cout << "Fizz\n";
                break;
            case 1:
                std::cout << i << '\n';
                break;
            case 2:
                std::cout << i << '\n';
                break;
        }
    }

    return 0;
}

