solution_code:
#include <random>
#include <iostream>

int first_below(std::mt19937& rng, int threshold, int max_draws)
{
    std::uniform_int_distribution<int> d{ 1, 100 };
    for (int i = 0; i < max_draws; ++i)
    {
        int v = d(rng);
        if (v < threshold)
            return v;
    }
    return -1;
}

int main()
{
    int threshold, max_draws;
    std::cin >> threshold >> max_draws;

    std::mt19937 rng{ 42u };
    std::cout << first_below(rng, threshold, max_draws) << '\n';

    return 0;
}
